const DEFAULT_CLASSES = ['S1 A','S1 B','S1 C','S2 A','S2 B','S2 C','S3 A','S3 B','S3 C','S4 A','S4 B','S4 C','S5 Arts','S5 Sciences','S6 Arts','S6 Sciences'];
function defaultClassObjects(){return DEFAULT_CLASSES.map(n=>{let level=(n.match(/S[1-6]/)||[''])[0];let isA=['S5','S6'].includes(level);let stream=isA?'':((n.match(/[ABC]$/)||[''])[0]);let section=isA?((n.match(/Arts|Sciences/i)||['Arts'])[0].replace(/^./,c=>c.toUpperCase())):'O-Level';let category=isA?'A-Level':'O-Level';return {name:n,level,stream,section,category,teacher:''};});}
function inferALevelSectionForStudent(studentName){let arr=(data.allocations&&data.allocations[studentName])||[];let science=['Mathematics','Physics','Chemistry','Biology','Agriculture'];return arr.some(x=>science.includes(x))?'Sciences':'Arts';}
function normalizeSections(){
  if(!Array.isArray(data.classes)) data.classes=[];
  data.classes=data.classes.filter(c=>{let n=String((c&&c.name)||'').trim();return !/^S[56](\s*[ABC])?$/i.test(n);});
  data.classes=data.classes.map(c=>{let n=String(c.name||'').trim();let level=(n.match(/S[1-6]/i)||[c.level||''])[0].toUpperCase();let isA=['S5','S6'].includes(level);let stream=isA?'':((n.match(/[ABC]$/i)||[c.stream||''])[0].toUpperCase());let section=isA?(/science/i.test(n)?'Sciences':(/art/i.test(n)?'Arts':(c.section==='Sciences'?'Sciences':'Arts'))):'O-Level';let name=isA?`${level} ${section}`:`${level} ${stream||'A'}`;return {...c,name,level,stream,section,category:isA?'A-Level':'O-Level'};});
  DEFAULT_CLASSES.forEach(n=>{if(!data.classes.some(c=>String(c.name).toLowerCase()===String(n).toLowerCase())){let obj=defaultClassObjects().find(c=>c.name===n);data.classes.push(obj);}});
  if(Array.isArray(data.students)){data.students.forEach(st=>{let level=classLevelOf(st.class_name||'');if(['S5','S6'].includes(level)){let current=String(st.class_name||'');let sec=/science/i.test(current)?'Sciences':(/art/i.test(current)?'Arts':inferALevelSectionForStudent(st.name));st.class_name=`${level} ${sec}`;}else if(['S1','S2','S3','S4'].includes(level)){let stream=(String(st.class_name||'').match(/[ABC]$/i)||['A'])[0].toUpperCase();st.class_name=`${level} ${stream}`;}});}
}
