let editingStudent = null;
let currentUser = JSON.parse(sessionStorage.getItem('namutumba_current_user') || 'null');
function roleOfUser(){return currentUser ? String(currentUser.role||'') : '';}
function isAdmin(){return roleOfUser().toLowerCase()==='admin';}
function isTeacher(){return roleOfUser().toLowerCase()==='teacher';}
function isBursar(){return roleOfUser().toLowerCase()==='bursar';}
function allowedPages(){
  if(isAdmin()) return pages.map(p=>p[0]);
  if(isTeacher()) return ['dashboard','teacherMarks'];
  if(isBursar()) return ['dashboard','fees','backup'];
  return ['dashboard'];
}
function isAllowedPage(id){return allowedPages().includes(id);}
function loginUser(){
  ensureDefaults();
  let u=(document.getElementById('loginUsername')||{}).value||'';
  let p=(document.getElementById('loginPassword')||{}).value||'';
  let user=(data.users||[]).find(x=>String(x.username||'').toLowerCase()===String(u).trim().toLowerCase() && String(x.password||'')===String(p) && String(x.status||'Active')==='Active');
  let err=document.getElementById('loginError');
  if(!user){ if(err){err.textContent='Wrong username/password or the user is disabled.';err.classList.add('show');} return; }
  currentUser={username:user.username,full_name:user.full_name,role:user.role,subject:user.subject||'',class_name:user.class_name||''};
  sessionStorage.setItem('namutumba_current_user', JSON.stringify(currentUser));
  showAppAfterLogin();
}
function logoutUser(){sessionStorage.removeItem('namutumba_current_user');currentUser=null;showLogin();}
function showLogin(){
  let ls=document.getElementById('loginScreen'), app=document.getElementById('appShell');
  if(ls)ls.style.display='flex'; if(app)app.classList.remove('active');
}
function showAppAfterLogin(){
  let ls=document.getElementById('loginScreen'), app=document.getElementById('appShell');
  if(ls)ls.style.display='none'; if(app)app.classList.add('active');
  let n=document.getElementById('currentUserName'), r=document.getElementById('currentUserRole');
  if(n)n.textContent=(currentUser&&currentUser.full_name)||'';
  if(r)r.textContent=((currentUser&&currentUser.role)||'') + (isTeacher()?` • ${currentUser.subject||'No subject assigned'} • ${currentUser.class_name||'No class assigned'}`:'');
  initNav(); renderAll(); let first=allowedPages()[0]||'dashboard'; page(first);
}
function teacherRestrictedNotice(){
  if(!isTeacher()) return '';
  return `<div class="restricted-note"><b>Teacher access:</b> You can enter marks only. Report cards and management pages are hidden. Assigned subject: <b>${esc(currentUser.subject||'Not assigned')}</b>; assigned class/section: <b>${esc(currentUser.class_name||'Not assigned')}</b>.</div>`;
}
function applyTeacherLimits(){
  let sub=document.getElementById('tmSubject'), cls=document.getElementById('tmClass');
  if(!sub||!cls) return;
  sub.disabled=false; cls.disabled=false;
  if(isTeacher()){
    if(currentUser.subject && [...sub.options].some(o=>o.value===currentUser.subject)){sub.value=currentUser.subject; sub.disabled=true;}
    if(currentUser.class_name && [...cls.options].some(o=>o.value===currentUser.class_name)){cls.value=currentUser.class_name; cls.disabled=true;}
  }
}
