function esc(s){return String(s??'').replace(/[&<>"]/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[m]));}
function dash(v){return (v===null||v===undefined||v===''||String(v).trim().toLowerCase()==='null'||String(v).trim().toLowerCase()==='undefined')?'-':v;}
