function uploadSchoolLogo(input){let file=input.files&&input.files[0]; if(!file)return; if(!file.type.startsWith('image/')){msg('schoolMsg','Please select an image file.');return;} let reader=new FileReader(); reader.onload=function(e){let img=new Image(); img.onload=function(){let max=500; let scale=Math.min(1,max/Math.max(img.width,img.height)); let c=document.createElement('canvas'); c.width=Math.max(1,Math.round(img.width*scale)); c.height=Math.max(1,Math.round(img.height*scale)); let ctx=c.getContext('2d'); ctx.clearRect(0,0,c.width,c.height); ctx.drawImage(img,0,0,c.width,c.height); data.school.logo=c.toDataURL('image/png'); localStorage.setItem('namutumba_sms_al_ol_v2', JSON.stringify(data)); updateLogoImages(); renderReport(); msg('schoolMsg','Logo saved and added to report cards.');}; img.src=e.target.result;}; reader.readAsDataURL(file);}
