function classLevelOf(className){let m=String(className||'').toUpperCase().match(/S[1-6]/);return m?m[0]:'';}
function isOLevelClass(className){return ['S1','S2','S3','S4'].includes(classLevelOf(className));}
function isALevelClass(className){return ['S5','S6'].includes(classLevelOf(className));}
function selectedTeacherClass(){return (document.getElementById('tmClass')||{}).value||'All Classes';}
function isMissedValue(v){let t=String(v??'').trim().toUpperCase();return t==='-'||t==='X';}
function isBlankValue(v){return v===null||v===undefined||String(v).trim()===''||String(v).trim().toLowerCase()==='null'||String(v).trim().toLowerCase()==='undefined';}
function subjectOrder(name){return data.subjects.findIndex(s=>s.name===name)}
function getCode(name){return (data.subjects.find(s=>s.name===name)||{}).code||name}
function isPrincipal(name){return (data.subjects.find(s=>s.name===name)||{}).category==='Principal'}
function comboFor(name){let arr=data.allocations[name]||[]; let principal=arr.filter(isPrincipal).sort((a,b)=>subjectOrder(a)-subjectOrder(b)).map(getCode); let subs=arr.filter(s=>!isPrincipal(s)).sort((a,b)=>subjectOrder(a)-subjectOrder(b)).map(getCode); if(!principal.length && !subs.length) return ''; return principal.join('/')+(subs.length?' + '+subs.join('/'):'');}
function page(id){if(!currentUser){showLogin();return;} if(!isAllowedPage(id)){alert('Access denied. Your role is not allowed to open this page.');id=allowedPages()[0]||'dashboard';}document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));let target=document.getElementById(id);if(target)target.classList.add('active');document.querySelectorAll('nav button').forEach(b=>b.classList.toggle('active',b.dataset.id===id)); if(id==='reportPage') renderReport(); if(id==='teacherMarks') renderTeacherMarksPage(); if(id==='olevelPage'||id==='alevelPage') renderLevelPages(); if(['s1Page','s2Page','s3Page','s4Page','s5Page','s6Page'].includes(id)) renderClassPages();}
function initNav(){let allowed=allowedPages();document.getElementById('nav').innerHTML=pages.filter(p=>allowed.includes(p[0])).map(p=>`<button data-id="${p[0]}" onclick="page('${p[0]}')">${p[1]}</button>`).join('');let first=document.querySelector('nav button'); if(first)first.classList.add('active')}
function msg(id,t){let el=document.getElementById(id);el.textContent=t;el.classList.add('show');setTimeout(()=>el.classList.remove('show'),2500)}
function fillSelect(id, items, valueKey='name'){let el=document.getElementById(id);if(!el)return;let cur=el.value;el.innerHTML=(items||[]).map(x=>`<option value="${esc(typeof x==='string'?x:x[valueKey])}">${esc(typeof x==='string'?x:x[valueKey])}</option>`).join(''); if([...el.options].some(o=>o.value===cur)) el.value=cur;}
