function defaultSubjectsForClass(cls){
  if(isOLevelClass(cls)) return OLEVEL_SUBJECTS.slice();
  let sec=String(cls||'').toLowerCase();
  let common=['General paper'];
  if(sec.includes('science')) return ['Mathematics','Physics','Chemistry','Biology','ICT','Sub-math','General paper'];
  if(sec.includes('art')) return ['History','Geography','CRE','Entrepreneurship','Literature','ICT','Sub-math','General paper'];
  return common;
}
function studentSectionName(cls){return isOLevelClass(cls)?'O-Level':(isALevelClass(cls)?'A-Level':'');}
function studentDepartmentName(cls){let level=classLevelOf(cls); if(['S1','S2','S3','S4'].includes(level)) return cls||'-'; if(['S5','S6'].includes(level)) return String(cls||'').replace(level,'').trim()||'-'; return '-';}
function admissionToStudentObject(a){return {name:a.name,class_name:a.class_name||'S4 A',sex:a.sex||'',house:a.house||'',dob:a.dob||'',guardian:a.guardian||'',contact:a.contact||'',address:'',notes:'',status:'Active',pay_code:a.pay_code||'',section:studentSectionName(a.class_name),department:studentDepartmentName(a.class_name)};}
function syncAdmissionToStudent(a){
  if(!a || String(a.status||'').toLowerCase()!=='admitted') return false;
  let obj=admissionToStudentObject(a);
  let idx=(data.students||[]).findIndex(s=>String(s.name||'').toLowerCase()===String(a.name||'').toLowerCase());
  if(idx>=0){ data.students[idx]={...data.students[idx],...obj}; }
  else { data.students.push(obj); }
  let oldAlloc=data.allocations[obj.name];
  if(!Array.isArray(oldAlloc) || oldAlloc.length===0) data.allocations[obj.name]=defaultSubjectsForClass(obj.class_name);
  return true;
}
