/* === Teacher assigned subject access patch ===
   Admin assigns subject + class/section in School Users.
   When that teacher logs in, the system opens Teacher Subject Marks automatically,
   locks the assigned subject/class, and allows saving only there.
*/
let editingUserIndex = null;
function teacherStartPage(){ return isTeacher() ? 'teacherMarks' : (allowedPages()[0]||'dashboard'); }

function showAppAfterLogin(){
  let ls=document.getElementById('loginScreen'), app=document.getElementById('appShell');
  if(ls)ls.style.display='none'; if(app)app.classList.add('active');
  let n=document.getElementById('currentUserName'), r=document.getElementById('currentUserRole');
  if(n)n.textContent=(currentUser&&currentUser.full_name)||'';
  if(r)r.textContent=((currentUser&&currentUser.role)||'') + (isTeacher()?` • ${currentUser.subject||'No subject assigned'} • ${currentUser.class_name||'No class assigned'}`:'');
  initNav(); renderAll(); page(teacherStartPage());
}

function applyTeacherLimits(){
  let sub=document.getElementById('tmSubject'), cls=document.getElementById('tmClass');
  if(!sub||!cls) return;
  sub.disabled=false; cls.disabled=false;
  if(isTeacher()){
    let assignedSubject=String(currentUser.subject||'');
    let assignedClass=String(currentUser.class_name||'');
    if(assignedSubject && [...sub.options].some(o=>o.value===assignedSubject)) sub.value=assignedSubject;
    if(assignedClass && [...cls.options].some(o=>o.value===assignedClass)) cls.value=assignedClass;
    sub.disabled=true; cls.disabled=true;
  }
}

function teacherRestrictedNotice(){
  if(!isTeacher()) return '';
  let good=currentUser.subject && currentUser.class_name;
  return `<div class="restricted-note"><b>Teacher access:</b> You are allowed to enter marks only for your assigned subject and class/section.<br>
  Subject: <b>${esc(currentUser.subject||'Not assigned')}</b> &nbsp; | &nbsp; Class/Section: <b>${esc(currentUser.class_name||'Not assigned')}</b>${good?'':'<br><span style="color:#b42318;font-weight:800">Ask the admin to assign your subject and class in School Users.</span>'}</div>`;
}

function saveUser(){
  let username=userName.value.trim();
  if(!username)return msg('userMsg','Enter username.');
  let rec={username,full_name:userFullName.value,role:userRole.value,password:userPass.value,subject:(userSubject&&userSubject.value)||'',class_name:(userClass&&userClass.value)||'',status:userStatus.value};
  if(String(rec.role).toLowerCase()==='teacher' && (!rec.subject || !rec.class_name)){
    return msg('userMsg','For a teacher, assign both subject and class/section before saving.');
  }
  if(editingUserIndex!==null && data.users[editingUserIndex]){
    data.users[editingUserIndex]={...data.users[editingUserIndex],...rec};
    editingUserIndex=null;
    let btn=document.getElementById('saveUserBtn'); if(btn)btn.textContent='Add User';
    msg('userMsg','User assignment updated. The teacher should log out and log in again to get the new assignment.');
  }else{
    if(data.users.some(u=>u.username.toLowerCase()===username.toLowerCase()))return msg('userMsg','User already exists. Use Edit to change the assignment.');
    data.users.push(rec); msg('userMsg','User added with assignment.');
  }
  userName.value='';userFullName.value='';userPass.value='';if(userSubject)userSubject.value='';if(userClass)userClass.value='';userStatus.value='Active';
  save();
}
function editUser(i){
  let u=data.users[i]; if(!u)return;
  editingUserIndex=i;
  userName.value=u.username||''; userFullName.value=u.full_name||''; userRole.value=u.role||'Teacher'; userPass.value=u.password||'';
  if(userSubject) userSubject.value=u.subject||''; if(userClass) userClass.value=u.class_name||''; userStatus.value=u.status||'Active';
  let btn=document.getElementById('saveUserBtn'); if(btn)btn.textContent='Update User Assignment';
  msg('userMsg','Editing user. Change subject/class then click Update User Assignment.');
}
function cancelUserEdit(){
  editingUserIndex=null; userName.value='';userFullName.value='';userPass.value='';if(userSubject)userSubject.value='';if(userClass)userClass.value='';userStatus.value='Active';
  let btn=document.getElementById('saveUserBtn'); if(btn)btn.textContent='Add User';
  msg('userMsg','Edit cancelled.');
}
function renderUsers(){
  let el=document.getElementById('usersTable');if(!el)return;
  let rows=(data.users||[]).map((u,i)=>`<tr><td>${i+1}</td><td><b>${esc(u.username)}</b></td><td>${esc(u.full_name||'')}</td><td>${esc(u.role)}</td><td>${esc(u.subject||'-')}</td><td>${esc(u.class_name||'-')}</td><td>${esc(u.password||'')}</td><td><span class="pill ${u.status==='Active'?'green':'red'}">${esc(u.status)}</span></td><td><button class="btn small" onclick="editUser(${i})">Edit Assignment</button> <span class="dangerlink" onclick="deleteUser(${i})">Remove</span></td></tr>`).join('');
  el.innerHTML=`<tr><th>No.</th><th>Username</th><th>Full Name</th><th>Role</th><th>Assigned Subject</th><th>Assigned Class / Section</th><th>Password</th><th>Status</th><th>Action</th></tr>${rows}`;
}

