/* ===== Patch: O-Level raw marks, marked-out-of conversion to /3 and /20 ===== */
function oLevelExistingRaw(m,n){
  if(m && !isBlankValue(m[`raw${n}`])) return inputValue(m[`raw${n}`]);
  if(m && !isBlankValue(m[`aoi${n}`])) return inputValue(m[`aoi${n}`]);
  return '';
}
function oLevelExistingOut(m,n){
  if(m && !isBlankValue(m[`out${n}`])) return inputValue(m[`out${n}`]);
  if(m && !isBlankValue(m[`aoi${n}`])) return '3';
  return '20';
}
function convertOLevelRawToThree(raw,out){
  let t=String(raw??'').trim();
  let max=Number(out);
  if(!isFinite(max)||max<=0) max=20;
  if(t==='') return {aoi:null,raw:null,out:max};
  if(t==='-' || t.toUpperCase()==='X') return {aoi:'X',raw:'X',out:max};
  let score=Number(t);
  if(!isFinite(score)) return {aoi:null,raw:null,out:max};
  let converted=(score/max)*3;
  if(converted<0) converted=0;
  if(converted>3) converted=3;
  return {aoi:Number(converted.toFixed(2)),raw:score,out:max};
}
